CREATE OR REPLACE FUNCTION fpb_get_resign_description (as_memno char) RETURNS varchar AS $body$
DECLARE

ls_resign_name varchar(1000);

BEGIN
  select  sc_mem_m_ucf_resign_cause.resign_cause_name
  into STRICT  ls_resign_name
  from sc_mem_m_resign_requestment ,
  sc_mem_m_ucf_resign_cause
  where (sc_mem_m_resign_requestment.resign_code = sc_mem_m_ucf_resign_cause.resign_cause_code)
  and (sc_mem_m_resign_requestment.membership_no = as_memno);
  return ls_resign_name;

  exception
  when no_data_found then return null;
  when others then CALL spa_dberror('fpb_get_resign_description');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
